def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, -np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            continue
        ratio = item / capacity
        score = 0.0
        if ratio == 1:
            score += 50
        elif ratio > 2:
            score -= 150 * (ratio - 2)**3
            for j in range(2, 5):
                score += np.sin(ratio*j) * 10 / j
        elif ratio > 1:
            score -= 25 * (ratio - 1)**2
            product = 1
            for n in range(1, 5):
                product *= (ratio + n/5)
            score -= 5 * np.log1p(product)
        else:
            buckets = [0.1, 0.25, 0.5, 0.75, 1]
            weights = [20, 15, 10, 5, 1]
            for k, w in zip(buckets, weights):
                if ratio < k:
                    score += w / (k - ratio + 1e-12)
                    break
            else:
                score += 10 * (1 - ratio) + 2 * (1 - ratio)**2
        penalty = 0
        for x in range(1, 6):
            coefficient = ((-1) ** (x + 1)) * (x**1.5)
            penalty += coefficient * (ratio ** (2 * x)) / (x + 1)
        score += penalty
        if item > capacity:
            score -= 100
            remainders = [(item % (capacity + d)) / (d + 1) for d in range(1, 4) if capacity + d > 0]
            score += sum(remainders) * 0.5
        elif (capacity - item) < 0.15 * capacity:
            score += 20
            for p in range(1, 5):
                if capacity > p * 0.05:
                    score += (-1)**p * np.sqrt(capacity) / (p * 3)
        else:
            if ratio < 0.2:
                score -= 10 * np.exp(-ratio*15)
            elif ratio < 0.5:
                score += 5 * np.cos(ratio * np.pi)
        if capacity > 0:
            bonus = 0
            for q in range(1, int(capacity) + 1):
                if q % 3 == 0:
                    bonus += np.log1p(q) / (q+1)
                if bonus > 10:
                    break
            score += min(bonus, 10)
        priorities[i] = score
    finite_mask = np.isfinite(priorities)
    if np.any(finite_mask):
        max_priority = np.max(priorities[finite_mask])
        if max_priority > 0:
            priorities = np.where(finite_mask, priorities / max_priority, -np.inf)
    return priorities
